from collections import defaultdict
from itertools import combinations

def solve(points: list[list[int]]) -> int:
    n = len(points)
    if n < 4:
        return 0

    # Precompute all pairs and their slopes (handling vertical lines)
    slope_map = defaultdict(list)

    for i, j in combinations(range(n), 2):
        x1, y1 = points[i]
        x2, y2 = points[j]
        if x1 == x2:
            slope = float('inf')  # represents vertical line
        else:
            slope = (y2 - y1) / (x2 - x1)
        slope_map[(i, j)] = slope

    # Now, group pairs by their slopes
    slope_groups = defaultdict(list)
    for pair, slope in slope_map.items():
        slope_groups[slope].append(pair)

    trapezoid_count = 0

    # For each slope, check combinations of two pairs (4 distinct points)
    for slope, pairs in slope_groups.items():
        if len(pairs) < 2:
            continue

        # Check all combinations of two distinct pairs
        for (a, b), (c, d) in combinations(pairs, 2):
            # Ensure all four points are distinct
            unique_points = {a, b, c, d}
            if len(unique_points) == 4:
                trapezoid_count += 1

    return trapezoid_count
